1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Quote — empty + base premiums per item type
6	  it("empty item list → premium 5 G (processing fee only)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	  it.todo("single sword → premium 105 G (100 base + 5 fee)");
14	  it.todo("single amulet → premium 65 G");
15	  it.todo("single staff → premium 85 G");
16	  it.todo("single potion → premium 45 G");
17	
18	  // Multiple items / components
19	  it.todo("two swords → premium 205 G (200 base + 5 fee)");
20	  it.todo("2 runes → premium 55 G (50 base + 5 fee)");
21	  it.todo("3 runes block → premium 65 G (60 base + 5 fee)");
22	  it.todo("4 runes no block → premium 105 G (100 base + 5 fee)");
23	  it.todo("7 runes → premium 180 G (175 base + 5 fee)");
24	  it.todo("2 runes + 1 moonstone no block → premium 80 G");
25	  it.todo("3 runes + 3 moonstones two blocks → premium 125 G");
26	
27	  // Item-specific modifiers
28	  it.todo("cursed sword newcomer → premium 165 G");
29	  it.todo("high enchantment (≥5) sword → premium 135 G (100 + 30 + 5)");
30	  it.todo("cursed + high enchantment sword → premium 185 G (100 + 50 + 30 + 5)");
31	  it.todo("policy with cursed sword + plain amulet → premium 215 G (160 + 50 + 5)");
32	
33	  // Policy-wide modifiers
34	  it.todo("loyal customer (≥2 years) sword → premium 85 G (100 − 20 + 5)");
35	  it.todo("first insurance surcharge sword first quote → premium 115 G (100 + 10 + 5)");
36	  it.todo("second quote contract gets 15% follow-up discount → premium 100 G (100 + 10 − 15 + 5)");
37	
38	  // Integration example
39	  it.todo("long-standing customer's second contract cursed sword enchantment 7 → premium 160 G");
40	
41	  // Rounding
42	  it.todo("rounds premium up in MHPCO's favor (197.5 → 198)");
43	
44	  // Claim — basic
45	  it.todo("standard sword damage 500 → payout 400 (full minus 100 deductible)");
46	  it.todo("rune damage 200 → payout 100");
47	  it.todo("high enchantment (≥8) sword damage 1000 → payout 400 (50% then deductible)");
48	  it.todo("dragon material sword damage 800 → payout 700 (full then deductible)");
49	  it.todo("dragon material + enchantment 9 sword damage 1000 → payout 400 (50% wins)");
50	  it.todo("multiple damages each get own deductible (sword 500 + amulet 300 → 600)");
51	  it.todo("cap exhaustion: two successive claims of 1500 each on sword (1000/2000 cap) → 1400 then 600");
52	  it.todo("rounds payout down in MHPCO's favor (350.5 → 350)");
53	
54	  // Error cases
55	  it.todo("quote with unknown item type → throws error");
56	  it.todo("claim referencing item not in policy → throws error");
57	  it.todo("claim with negative damage amount → throws error");
58	  it.todo("claim with more damages of a type than policy covers → throws error");
59	});
